// export default Register


import React, { useState } from 'react';

function Register() {
    const [formData, setFormData] = useState({
        email: '',
        password: '',
        firstName: '',
        lastName: '',
        mobile: '',
        emailError: '',
        passwordError: '',
        mobileError: ''
    });

    // Handle Input Change
    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    // Email Validation
    const validateEmail = (e) => {
        const value = e.target.value;
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        setFormData({
            ...formData,
            email: value,
            emailError: emailRegex.test(value) ? '' : 'Invalid email format'
        });
    };

    // Password Validation (Exactly 8 characters)
    const validatePassword = (e) => {
        const value = e.target.value;
        setFormData({
            ...formData,
            password: value,
            passwordError: value.length === 8 ? '' : 'Password must be exactly 8 characters'
        });
    };

    // Mobile Number Validation (Only numbers, exactly 10 digits)
    const validateMobile = (e) => {
        const value = e.target.value.replace(/\D/g, ''); // Remove non-numeric characters
        setFormData({
            ...formData,
            mobile: value,
            mobileError: value.length === 10 ? '' : 'Mobile number must be exactly 10 digits'
        });
    };

    // Handle Form Submission
    const handleSubmit = (e) => {
        e.preventDefault();

        if (!formData.email || formData.emailError || !formData.password || formData.passwordError || !formData.mobile || formData.mobileError) {
            alert("Please fix validation errors before submitting.");
            return;
        }

        alert("Form submitted successfully!");
    };

    return (
        <div className='Login-form d-flex align-items-center justify-content-center vh-100'>
            <div className="container">
                <div className="row justify-content-center align-items-center">
                    <div className="col-md-4"></div>
                    <div className="form col-md-4 border border-light py-4 rounded-4 shadow">
                        <form className="text-light" onSubmit={handleSubmit}>
                            <h1 className="text-light text-center">Register</h1>

                            {/* Email */}
                            <div className="mb-3 m-3">
                                <label htmlFor="email" className="form-label">Email address</label>
                                <input
                                    type="email"
                                    className="form-control"
                                    id="email"
                                    name="email"
                                    placeholder="abcd@gmail.com"
                                    value={formData.email}
                                    onChange={validateEmail}
                                />
                                {formData.emailError && <small className="text-danger">{formData.emailError}</small>}
                            </div>

                            {/* Password */}
                            <div className="mb-3 m-3">
                                <label htmlFor="password" className="form-label">Password</label>
                                <input
                                    type="password"
                                    className="form-control"
                                    id="password"
                                    name="password"
                                    placeholder="Enter 8-digit password"
                                    value={formData.password}
                                    onChange={validatePassword}
                                />
                                {formData.passwordError && <small className="text-danger">{formData.passwordError}</small>}
                            </div>

                            {/* First Name */}
                            <div className="mb-3 m-3">
                                <label htmlFor="firstName" className="form-label">First Name</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    id="firstName"
                                    name="firstName"
                                    placeholder="First Name"
                                    value={formData.firstName}
                                    onChange={handleChange}
                                />
                            </div>

                            {/* Last Name */}
                            <div className="mb-3 m-3">
                                <label htmlFor="lastName" className="form-label">Last Name</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    id="lastName"
                                    name="lastName"
                                    placeholder="Last Name"
                                    value={formData.lastName}
                                    onChange={handleChange}
                                />
                            </div>

                            {/* Mobile Number */}
                            <div className="mb-3 m-3">
                                <label htmlFor="mobile" className="form-label">Mobile No.</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    id="mobile"
                                    name="mobile"
                                    placeholder="Enter your number"
                                    value={formData.mobile}
                                    onChange={validateMobile}
                                    maxLength="10"
                                />
                                {formData.mobileError && <small className="text-danger">{formData.mobileError}</small>}
                            </div>

                            {/* Buttons */}
                            <div>
                                <button className="btn btn-danger px-3 m-3" type="submit">Submit</button>
                                <button className="btn btn-danger px-3" type="button">Close</button>
                            </div>

                        </form>
                    </div>
                    <div className="col-md-4"></div>
                </div>
            </div>
        </div>
    );
}

export default Register;
